import { useState, useCallback } from 'react';

import constFlaskURL from '../consts/constFlaskURL'

export const transformDataForTable = (data) => {
    if (!Array.isArray(data) || data.length === 0) 
    {
        return [];
    }

    return data.map(
        (item, index) => (
            {
                id: index + 1,
                ...item
            }
        )
    );
};
